import React from 'react';
import { useNetwork } from '../contexts/NetworkContext';

const TopologyMap = () => {
    const { devices, loading } = useNetwork();

    if (loading) {
        return <div style={{ color: '#9ca3af', marginTop: '2rem' }}>Loading map data...</div>;
    }

    return (
        <div style={{ marginTop: '2rem', backgroundColor: '#1f2937', padding: '2rem', borderRadius: '0.5rem', minHeight: '500px', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center' }}>
            <h2 style={{ fontSize: '1.5rem', color: '#f3f4f6', alignSelf: 'flex-start', margin: '0 0 2rem 0' }}>Live Network Topology</h2>
            
            {/* The "Cloud" / Core connection */}
            <div style={{ padding: '1rem 2rem', backgroundColor: '#374151', borderRadius: '999px', color: '#f3f4f6', fontWeight: 'bold', marginBottom: '3rem', border: '2px solid #4b5563' }}>
                ☁️ Internet / WAN
            </div>

            {/* The Devices Grid */}
            <div style={{ display: 'flex', gap: '2rem', flexWrap: 'wrap', justifyContent: 'center' }}>
                {devices.map(device => (
                    <div key={device.id} style={{ display: 'flex', flexDirection: 'column', alignItems: 'center' }}>
                        {/* Simulated wire connecting up to the core */}
                        <div style={{ width: '2px', height: '40px', backgroundColor: device.status === 'ONLINE' ? '#10b981' : '#ef4444', marginBottom: '0.5rem' }}></div>
                        
                        {/* Device Node */}
                        <div style={{
                            padding: '1.5rem',
                            backgroundColor: '#111827',
                            borderRadius: '50%',
                            border: `4px solid ${device.status === 'ONLINE' ? '#10b981' : '#ef4444'}`,
                            width: '120px',
                            height: '120px',
                            display: 'flex',
                            flexDirection: 'column',
                            alignItems: 'center',
                            justifyContent: 'center',
                            textAlign: 'center',
                            boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)'
                        }}>
                            <span style={{ fontSize: '1.5rem', marginBottom: '0.5rem' }}>
                                {device.name.includes('Firewall') || device.name.includes('FortiGate') ? '🧱' : '🖧'}
                            </span>
                            <span style={{ fontSize: '0.75rem', color: '#f3f4f6', wordBreak: 'break-word' }}>{device.name}</span>
                        </div>
                    </div>
                ))}
            </div>
        </div>
    );
};

export default TopologyMap;
